import React, { useState, useEffect } from "react"
import { Link } from "gatsby"
import Layout from "../components/layout"
import Bg from "../images/bg.png"
import Dot from "../images/dot.svg"
import { ChevronRightIcon } from "@heroicons/react/16/solid"
import { ChevronDownIcon } from "@heroicons/react/16/solid"
import Strategies from "../components/strategies.json"
import Select from "react-select"
import Accordion from "../components/accordion"

const WhatIsThePlan = () => {
  const strategies = { ...Strategies }
  const [element, setElement] = useState("")
  const [party, setParty] = useState([])
  const elementOptions = [
    { value: "Transportation", label: "Transportation" },
    { value: "Economy", label: "Economy" },
    { value: "Communities", label: "Communities" },
    { value: "Environment", label: "Environment" },
    {
      value: "Infrastructure & Utility Services",
      label: "Infrastructure and Utility Services",
    },
  ]
  const partyOptions = [
    { value: "Municipalities", label: "Municipalities" },
    { value: "DVRPC", label: "DVRPC" },
    { value: "Counties", label: "Counties" },
    { value: "DOTs", label: "DOTs" },
    { value: "Transit Agencies", label: "Transit Agencies" },
    { value: "Federal Agencies", label: "Federal Agencies" },
    { value: "State Agencies", label: "State Agencies" },
    { value: "TMAs", label: "TMAs" },
    {
      value: "Ports & Freight Operators",
      label: "Ports & Freight Operators",
    },
    { value: "Emergency Responders", label: "Emergency Responders" },
    { value: "Toll Authorities", label: "Toll Authorities" },
    { value: "Nonprofits", label: "Nonprofits" },
    { value: "School Districts", label: "School Districts" },
    { value: "Academia", label: "Academia" },
    {
      value: "Professional Organizations",
      label: "Professional Organizations",
    },
    { value: "Private Sector", label: "Private Sector" },
    { value: "PPP", label: "PPP" },
    {
      value: "Economic Development Organizations",
      label: "Economic Development Organizations",
    },
    {
      value: "Mission-Driven Lending Institutions",
      label: "Mission-Driven Lending Institutions",
    },
    { value: "Utilities", label: "Utilities" },
    {
      value: "Regional Transmission Organizations",
      label: "Regional Transmission Organizations",
    },
  ]
  const elementHex = {
    Transportation: "#423d59",
    Economy: "#711e53",
    Communities: "#004c6d",
    Environment: "#006227",
    "Infrastructure & Utility Services": "#147272",
  }
  const elementSecHex = {
    Transportation: "#d3dbef",
    Economy: "#ddd4e0",
    Communities: "#cce7f6",
    Environment: "#d7eade",
    "Infrastructure & Utility Services": "#c7e6e9",
  }
  const [filteredStrategies, setFilteredStrategies] = useState()
  const [filter, setFilter] = useState("")
  useEffect(() => {
    let ret = []
    if (element.length > 0) {
      element.map(el => (ret = [...ret, ...strategies[el.value].strategies]))
      ret = ret.filter(
        data =>
          data.name.toLowerCase().includes(filter.toLowerCase()) ||
          data.description.toLowerCase().includes(filter.toLowerCase())
      )
    }
    setFilteredStrategies(ret)
  }, [element, party, setFilteredStrategies, filter])

  return (
    <Layout>
      <div className="bg-[#cbe5f3] flex flex-col items-center">
        <div className="w-full h-full">
          <img
            alt="Stylized image of the DVPRC region."
            src={Bg}
            className="absolute object-cover h-2/5 w-full"
          />
          <div className="flex text-white font-bold w-[68%] mx-auto px-7 z-50 relative items-center mt-4">
            <Link className="underline text-white" to="/">
              Home
            </Link>
            <ChevronRightIcon width="1.5%" />
            <Link className="underline text-white" to="/vision">
              Vision
            </Link>
            <ChevronRightIcon width="1.5%" />
            <Link className="text-white">Strategies</Link>
          </div>
        </div>
        <div className="text-[#dfebf5] w-full bg-[#0c2e39] flex flex-col relative px-10 py-6 space-y-4 mt-[10%]">
          <div className="md:w-[68%] mx-auto space-y-4">
            <h2 className="md:text-3xl text-xl font-bold">
              Strategies: Turning Vision into Action
            </h2>
            <p className="md:text-2xl text-lg pb-0 z-50">
              Change won't come overnight, and it won't happen by doing things
              the same old way. Achieving this vision will take bold action and
              collaboration acrosss the region, with everyone playing a part.
            </p>
            <p className="md:text-2xl text-lg pb-0 z-50">
              Even though each goal and strategy shows up just once,
              crosscutting themes&mdash;like how goods move around the region,
              how we use land, how easy it is to get where you need to go, and
              how we use new technology&mdash;pop up throughout the plan.
            </p>
          </div>
        </div>
        <div className="md:w-[68%] relative border-l-4 border-[#063446]">
          <div className="flex items-center w-full md:p-6 p-2 relative">
            <Dot
              width="3%"
              className="md:absolute md:block -left-[1.5%] hidden"
            />
            <p className="text-[#063446] md:text-2xl text-lg">
              Explore how the region's five Plan Elements are being put into
              action through <strong>high-level strategies</strong> and specific{" "}
              <strong>implementation actions</strong>. Filter by topics and{" "}
              <strong>responsible parties</strong>, or use the keyword search to
              find the initiatives most relevant to your work.
            </p>
          </div>
        </div>
        <div className="md:w-[68%] w-full relative border-l-4 border-[#063446]">
          <div className="flex w-full md:p-6 md:pt-0 relative flex-col">
            <strong>Start your search:</strong>
            <span>Element</span>
            <Select
              options={elementOptions}
              isMulti
              value={element}
              onChange={setElement}
              styles={{
                multiValue: (provided, { data }) => ({
                  ...provided,
                  backgroundColor: elementHex[data.value],
                  color: "#ffffff",
                }),
                multiValueLabel: (provided, { data }) => ({
                  ...provided,
                  color: "#ffffff",
                }),
              }}
            />
            <span>Responsible Parties</span>
            <Select
              options={partyOptions}
              isMulti
              value={party}
              onChange={setParty}
              styles={{
                multiValue: (provided, { data }) => ({
                  ...provided,
                  backgroundColor: "#063446",
                  color: "#ffffff",
                }),
                multiValueLabel: (provided, { data }) => ({
                  ...provided,
                  color: "#ffffff",
                }),
              }}
            />
            <span>Keyword</span>
            <input
              type="text"
              onChange={e => setFilter(e.target.value)}
              value={filter}
              className="input block w-full rounded-sm border border-gray-200 bg-gray-50 bg-none py-2 px-4 text-base leading-6 text-black text-opacity-80 transition-all"
            />
            {filteredStrategies && filteredStrategies.length > 0 ? (
              <div className="text-gray-500">
                Search results: {filteredStrategies.length}
              </div>
            ) : null}
          </div>
        </div>

        <div className="w-full bg-[#eaf3fb] relative">
          <div className="border-l-4 border-[#0c2e39] md:w-[68%] mx-auto">
            <div className="flex flex-col space-y-4 p-6 pt-0">
              <div className="flex w-full md:p-4 relative flex-col space-y-4">
                {filteredStrategies &&
                  filteredStrategies.length > 0 &&
                  filteredStrategies.map((strategy, idx) => (
                    <>
                      {filteredStrategies[idx - 1]?.element !==
                        strategy.element && (
                        <h2 className="md:text-2xl text-lg text-[#063446] font-bold">
                          Strategies for Achieving{" "}
                          <span style={{ color: elementHex[strategy.element] }}>
                            {strategy.element}
                          </span>{" "}
                          Our Goals
                        </h2>
                      )}
                      <div className="flex items-start space-x-2">
                        <p
                          className="md:text-xl text-lg font-bold"
                          style={{ color: elementHex[strategy.element] }}
                        >
                          {strategy.id})
                        </p>

                        <div>
                          <p
                            className="font-bold text-xl"
                            style={{ color: elementHex[strategy.element] }}
                          >
                            {strategy.name}
                          </p>
                          <p>{strategy.description}</p>
                          <div
                            className="p-2 px-4"
                            style={{
                              backgroundColor: elementSecHex[strategy.element],
                            }}
                          >
                            <Accordion
                              label="Implementation Actions"
                              color={elementHex[strategy.element]}
                              size="1rem"
                            >
                              {strategy.actions.map(action => {
                                return (
                                  <>
                                    {party.length > 0 &&
                                      action.tags.some(value =>
                                        party
                                          .map(term => term.value)
                                          .includes(value)
                                      ) && <p>{action.description}</p>}
                                    {!party.length && (
                                      <p>
                                        {action.description} (
                                        {action.tags.join(", ")})
                                      </p>
                                    )}
                                  </>
                                )
                              })}
                            </Accordion>
                          </div>
                        </div>
                      </div>
                    </>
                  ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </Layout>
  )
}

export default WhatIsThePlan
